import Foundation

let questions5: [QuizQuestion] = [
QuizQuestion(id:331,question:"Quem foi Rute e por que sua história é importante?",options:["Uma rainha de Israel","Uma profetisa de Judá","A esposa do rei Saul","Uma moabita que seguiu sua"],correctIndex:3,explanation:"Rute, moabita, declarou: 'Onde tu morreres, morrerei eu.' Casou-se com Boaz e tornou-se bisavó de Davi e antepassada de Jesus.",reference:"Rute 1:16; Mateus 1:5",category:.geral,propheticMeaning:"Boaz como 'parente redentor' (go'el) que redime Rute é tipo de Cristo que nos redime da nossa pobreza espiritual — comprando-nos de volta para a família de Deus."),
QuizQuestion(id:332,question:"Quem foi Ester e qual foi seu ato heroico?",options:["Uma jovem judia que","Uma rainha de Israel","Uma profetisa de Judá","A filha de Salomão"],correctIndex:0,explanation:"Ester, rainha persa de origem judaica, arriscou a vida ao entrar sem convite à presença do rei para revelar o plano de extermínio dos judeus elaborado por Hamã.",reference:"Ester 4:14; 5:1-2",category:.geral,propheticMeaning:"'Quem sabe se para um momento como este chegaste ao reino?' (Et 4:14) — princípio eterno de que Deus coloca cada crente estrategicamente em sua época para cumprir seu propósito."),
QuizQuestion(id:333,question:"Qual é a história de Jó?",options:["Um rei que perdeu seu reino","Um homem justo que sofreu enormemente","Um profeta que fugiu de Deus","Um sacerdote que pecou no templo"],correctIndex:1,explanation:"Jó sofreu a perda de filhos, riqueza e saúde, mas manteve sua integridade. Após questionar a Deus, Deus respondeu do redemoinho e restaurou Jó em dobro.",reference:"Jó 1:21; 42:10",category:.geral,propheticMeaning:"Jó 19:25-26: 'Sei que o meu Redentor vive... e em minha carne verei a Deus' — a mais clara declaração de ressurreição corporal e esperança messiânica no livro mais antigo da Bíblia."),
QuizQuestion(id:334,question:"O que Provérbios 3:5-6 ensina?",options:["'O temor do Senhor é o princípio da","'O orgulho precede a queda'","'Confia no Senhor de todo o teu coração","'A mulher virtuosa, quem a achará?'"],correctIndex:2,explanation:"Provérbios 3:5-6: 'Confia no Senhor de todo o teu coração e não te apoies no teu próprio entendimento; reconhece-o em todos os teus caminhos, e ele endireitará as tuas veredas.'",reference:"Provérbios 3:5-6",category:.geral,propheticMeaning:"Confiar em Deus acima do próprio entendimento é o coração da fé bíblica — o antídoto para a autonomia pecaminosa de Adão que queria ser 'como Deus' pelo próprio conhecimento (Gn 3:5)."),
QuizQuestion(id:335,question:"Qual é o livro de Eclesiastes sobre?",options:["As leis de Israel","A sabedoria de Salomão sobre riqueza","Os profetas do reino do norte","A busca por sentido da vida sem Deus e"],correctIndex:3,explanation:"Eclesiastes descreve a vaidade de tudo 'debaixo do sol' — riqueza, sabedoria, prazer — concluindo: 'Teme a Deus e guarda os seus mandamentos, porque isto é o dever de todo homem.'",reference:"Eclesiastes 12:13",category:.geral,propheticMeaning:"A 'vaidade' de Eclesiastes aponta para a necessidade de vida 'acima do sol' — aquilo que Cristo oferece: vida eterna que transcende a futilidade temporal (Jo 10:10)."),
QuizQuestion(id:336,question:"O que é o Cântico dos Cânticos?",options:["Uma celebração do amor humano no","Um hino de adoração a Deus","Uma coleção de lamentos","Uma profecia sobre o Messias"],correctIndex:0,explanation:"O Cântico dos Cânticos celebra o amor esponsal e é interpretado alegórica e/ou literalmente como imagem do amor de Deus pelo seu povo.",reference:"Cântico dos Cânticos 2:16",category:.geral,propheticMeaning:"Paulo em Efésios 5:32 chama o casamento de 'grande mistério' referindo-se a Cristo e à Igreja — o Cântico antecipa o amor do 'noivo' (Jesus) pela 'noiva' (Igreja) em Apocalipse 19:7."),
QuizQuestion(id:337,question:"Qual é o Salmo 91 sobre?",options:["A queda de Sião","A proteção divina para quem","O julgamento dos ímpios","A criação do universo"],correctIndex:1,explanation:"O Salmo 91 promete proteção divina ao que 'habita no esconderijo do Altíssimo e descansa à sombra do Onipotente.'",reference:"Salmos 91:1-2",category:.geral,propheticMeaning:"O diabo citou o Salmo 91 para tentar Jesus (Mt 4:6) — a proteção prometida é para quem confia, não para quem testa a Deus. Cristo resistiu com 'Está escrito também' — aprendemos a interpretar Escritura com Escritura."),
QuizQuestion(id:338,question:"Qual é o Salmo 110 e sua importância messiânica?",options:["O Salmo do Pastor","O Salmo da criação","O Salmo mais citado no NT: 'Disse","O Salmo de Davi sobre o exílio"],correctIndex:2,explanation:"O Salmo 110 é o mais citado no NT — Jesus usou-o para demonstrar que o Messias é mais do que filho de Davi: é o Senhor sentado à direita de Deus.",reference:"Salmos 110:1; Mateus 22:44",category:.geral,propheticMeaning:"O Salmo 110:4 também declara o Messias como 'sacerdote para sempre segundo a ordem de Melquisedeque' — título central em Hebreus para explicar o sumo sacerdócio eterno de Cristo."),
QuizQuestion(id:339,question:"Qual é a diferença entre o tabernáculo e o templo?",options:["São a mesma coisa","O tabernáculo foi construído por Salomão","O templo era portátil e o tabernáculo","O tabernáculo era a tenda portátil de..."],correctIndex:3,explanation:"O tabernáculo (Êx 25-40) era portátil, construído no deserto. O templo foi o edifício permanente de Salomão em Jerusalém (1 Rs 6).",reference:"Êxodo 25:8-9; 1 Reis 6:1",category:.geral,propheticMeaning:"Tanto tabernáculo quanto templo eram 'sombras das coisas celestiais' (Hb 8:5) — tipos do corpo de Cristo (Jo 2:21) e da Igreja como templo do Espírito (1 Co 3:16)."),
QuizQuestion(id:340,question:"O que foram as tribos perdidas de Israel?",options:["As dez tribos do reino do norte","Tribos que foram para o Egito","Tribos que abandonaram a fé","As tribos que não existiram"],correctIndex:0,explanation:"O reino do norte de Israel (dez tribos) foi conquistado pela Assíria em 722 a.C. e as populações foram deportadas e dispersas.",reference:"2 Reis 17:6",category:.geral,propheticMeaning:"Ezequiel 37:19-22 profetiza a reunificação futura de 'Judá' e 'Israel' num só povo sob o Messias — cumprimento antecipado na Igreja onde todos são 'um em Cristo' (Gl 3:28)."),
QuizQuestion(id:341,question:"Qual foi o papel de Esdras no retorno do exílio?",options:["Ele liderou a batalha contra Babilônia","Sacerdote e escriba que liderou","Ele construiu o segundo templo","Foi governador de Judá"],correctIndex:1,explanation:"Esdras, sacerdote e escriba, liderou um grupo de exilados de volta à Judá e realizou uma grande reforma religiosa lendo publicamente a lei.",reference:"Esdras 7:10",category:.geral,propheticMeaning:"Esdras como escriba que 'preparou seu coração para buscar a lei do Senhor e praticá-la' é modelo do discípulo que primeiro aplica a Palavra a si mesmo antes de ensinar outros."),
QuizQuestion(id:342,question:"Qual foi o papel de Neemias?",options:["Profeta que anunciou o exílio","Sacerdote que reformou o culto","Governador que liderou a","Rei de Judá após o exílio"],correctIndex:2,explanation:"Neemias, copeiro do rei persa, recebeu permissão para reconstruir os muros de Jerusalém e os completou em apenas 52 dias apesar de grande oposição.",reference:"Neemias 6:15",category:.geral,propheticMeaning:"Neemias reconstruindo os muros com uma mão na espada e outra na ferramenta é imagem do crente que trabalha e vigia — construtores do Reino que vivem em tensão com o mundo."),
QuizQuestion(id:343,question:"Qual é a importância dos Salmos para a adoração cristã?",options:["São apenas história judaica","São apenas profecias","São usados apenas em funerais","São o hinário inspirado de Israel"],correctIndex:3,explanation:"Os Salmos são o livro de adoração da Bíblia — usados pelo Israel do AT, por Jesus e pela Igreja ao longo dos séculos, expressando louvor, lamento, confiança e esperança.",reference:"Colossenses 3:16",category:.geral,propheticMeaning:"Jesus citou Salmos na cruz (Sl 22:1; 31:5) — mostrando que o livro de adoração formou a linguagem espiritual de Cristo nas horas mais críticas. Salmos molda a oração e adoração cristã até hoje."),
QuizQuestion(id:344,question:"Qual é a missão da Igreja segundo Efésios 3?",options:["Tornar conhecida às potestades celestiais","Construir edifícios religiosos","Guardar a lei mosaica","Preparar o povo apenas para a vida após a..."],correctIndex:0,explanation:"Efésios 3:10: a intenção de Deus é que 'pela Igreja seja conhecida às principalidades e potestades nos lugares celestiais a multiforme sabedoria de Deus.'",reference:"Efésios 3:10",category:.geral,propheticMeaning:"A Igreja unindo judeus e gentios é a maior demonstração da sabedoria de Deus diante de todas as potências — o 'mistério' revelado que os profetas e anjos desejavam entender (1 Pe 1:12)."),
QuizQuestion(id:345,question:"O que Paulo ensina sobre eleição em Romanos 8-9?",options:["Deus salva a todos automaticamente","Deus soberanamente escolheu em Cristo","A salvação depende inteiramente da","Eleição é apenas a escolha de Israel como..."],correctIndex:1,explanation:"Romanos 8:29-30 e 9:14-18 ensinam a eleição soberana de Deus: 'predestinou, chamou, justificou, glorificou' — não por obras humanas mas pela misericórdia divina.",reference:"Romanos 8:29-30; Efésios 1:4",category:.geral,propheticMeaning:"A eleição está 'em Cristo' (Ef 1:4) — não eleição de indivíduos abstratos mas dos que estão no Eleito. A soberania de Deus e a responsabilidade humana coexistem na Escritura sem solução racional plena."),
QuizQuestion(id:346,question:"O que é o 'mistério' que Paulo revela em Efésios e Colossenses?",options:["O fim do mundo","A existência da Trindade","A união de judeus e gentios num","A natureza da ressurreição"],correctIndex:2,explanation:"O 'mistério' de Paulo é que os gentios são 'co-herdeiros, do mesmo corpo e coparticipantes da promessa em Cristo Jesus' (Ef 3:6) — algo escondido por eras.",reference:"Efésios 3:4-6; Colossenses 1:26-27",category:.geral,propheticMeaning:"'Cristo em vós, a esperança da glória' (Cl 1:27) resume o mistério: o Deus que habitava no templo agora habita em cada crente — democratização radical da presença divina."),
QuizQuestion(id:347,question:"Quais são os sete 'Eu sou' de Jesus em João?",options:["'Eu sou o caminho","'Eu sou o Filho de Deus' (sete vezes)","'Eu sou o Rei' (sete vezes)","'Eu sou o pão da vida"],correctIndex:3,explanation:"Os sete 'Eu Sou' de João revelam as dimensões de Cristo: pão da vida (6:35), luz do mundo (8:12), porta (10:9), bom pastor (10:11), ressurreição (11:25), caminho/verdade/vida (14:6) e videira (15:1).",reference:"João 6:35; 8:12; 10:9,11; 11:25; 14:6; 15:1",category:.geral,propheticMeaning:"Cada 'Eu Sou' ecoa o Nome divino de Êxodo 3:14 e responde a uma necessidade humana fundamental: fome, escuridão, busca de caminho, desamparo, morte, dúvida e improdutividade."),
QuizQuestion(id:348,question:"O que Jesus ensinou sobre o novo nascimento em João 3?",options:["'Ninguém pode ver o reino de Deus se não","Que devemos ser rebatizados","Que devemos ser moralmente melhores","Que apenas judeus precisam renascer"],correctIndex:0,explanation:"Jesus disse a Nicodemos: quem não nascer de água e Espírito não pode entrar no reino. O nascimento do Espírito é necessário para todos — não apenas os visivelmente pecadores.",reference:"João 3:3-8",category:.geral,propheticMeaning:"João 3:3 e Ezequiel 36:26-27 são paralelos: 'darei-vos coração novo' é a promessa cujo cumprimento Jesus revela como 'nascer de novo pelo Espírito.'"),
QuizQuestion(id:349,question:"O que significa 'teologia da cruz' versus 'teologia da glória'?",options:["A cruz foi glorificada","A teologia da cruz reconhece que Deus se","O sofrimento é necessário para a salvação","Apenas pastores precisam sofrer"],correctIndex:1,explanation:"Lutero distinguiu: a teologia da glória busca Deus nas alturas; a teologia da cruz o encontra na humilhação, fraqueza e sofrimento — como Paulo em 1 Co 1:23-25.",reference:"1 Coríntios 1:23-25",category:.geral,propheticMeaning:"'A loucura de Deus é mais sábia do que os homens' (1 Co 1:25) — a cruz, escândalo para judeus e loucura para gregos, é o poder de Deus para salvação. Deus inverte toda a sabedoria humana."),
QuizQuestion(id:350,question:"O que Paulo quer dizer com 'mortificar as obras da carne'?",options:["Punir o corpo fisicamente","Não comer carne","Matar continuamente","Praticar jejum extremo"],correctIndex:2,explanation:"Romanos 8:13: 'Se pelo Espírito mortificais as obras do corpo, vivereis.' A mortificação é um processo contínuo de rejeição da natureza pecaminosa pelo poder do Espírito.",reference:"Romanos 8:13; Colossenses 3:5",category:.geral,propheticMeaning:"A mortificação não é auto-salvação mas cooperação com o Espírito — o crente 'pode porque o Espírito pode.' É a santificação progressiva entre justificação e glorificação."),
QuizQuestion(id:351,question:"Qual é a promessa de Mateus 18:20?",options:["'Pedi e recebereis'","'Aquele que perseverar até o fim será","'Todo aquele que crer será salvo'","'Onde dois ou três estiverem reunidos em"],correctIndex:3,explanation:"Mateus 18:20: 'Porque onde dois ou três estiverem reunidos em meu nome, ali estou no meio deles' — a presença de Cristo na reunião da Igreja.",reference:"Mateus 18:20",category:.geral,propheticMeaning:"A presença de Cristo 'no meio' da assembleia cumpre Mateus 1:23 — Emanuel, 'Deus conosco', não apenas no nascimento mas em cada reunião da Igreja em seu nome."),
QuizQuestion(id:352,question:"O que é a 'reconciliação' em 2 Coríntios 5?",options:["'Deus estava em Cristo","Paz entre nações","Perdão entre cristãos","Acordo político"],correctIndex:0,explanation:"2 Coríntios 5:19: 'Deus estava em Cristo reconciliando o mundo consigo mesmo.' A reconciliação é a restauração da relação entre Deus e a humanidade pecadora.",reference:"2 Coríntios 5:18-21",category:.geral,propheticMeaning:"'Nós somos embaixadores de Cristo... rogamos-vos... que vos reconcilieis com Deus' (2 Co 5:20) — o cristão não apenas recebe reconciliação mas é comissionado a proclamá-la."),
QuizQuestion(id:353,question:"O que Paulo chama de 'andar pela fé e não pelo que se vê'?",options:["Ignorar a realidade física","Viver baseado nas realidades","Negar o sofrimento","Recusar medicina"],correctIndex:1,explanation:"2 Coríntios 5:7: 'Andamos por fé e não pelo que se vê.' O crente orienta sua vida pelas realidades eternas reveladas por Deus, não apenas pelo visível e temporário.",reference:"2 Coríntios 5:7",category:.geral,propheticMeaning:"Hebreus 11 lista heróis que 'viram de longe as promessas, saúdaram-nas, e confessaram que eram peregrinos na terra' — a fé reorienta toda a existência para o eterno."),
QuizQuestion(id:354,question:"O que Paulo ensina em Filipenses 4:6-7 sobre a ansiedade?",options:["Ignore as preocupações","Seja mais otimista","'Por nada estejais ansiosos","Finja que não há problemas"],correctIndex:2,explanation:"Filipenses 4:6-7: 'Por nada estejais ansiosos; mas em tudo, pela oração... apresentai os vossos pedidos a Deus; e a paz de Deus, que transcende todo o entendimento, guardará os vossos corações em Cristo.'",reference:"Filipenses 4:6-7",category:.geral,propheticMeaning:"A paz que 'transcende o entendimento' não é produto de circunstâncias favoráveis mas da comunhão com Cristo — cumprimento de João 14:27: 'A minha paz vos dou; não como o mundo a dá.'"),
QuizQuestion(id:355,question:"O que é o 'Templo de Ezequiel' profetizado em Ezequiel 40-48?",options:["O segundo templo de Zorobabel","O tabernáculo de Moisés","O templo de Herodes","Uma visão profética do templo"],correctIndex:3,explanation:"Ezequiel 40-48 contém a visão de um templo grandioso com proporções maiores que qualquer templo histórico — interpretado como templo milenar futuro ou símbolo escatológico.",reference:"Ezequiel 40:2-4",category:.geral,propheticMeaning:"O rio de vida que flui do templo de Ezequiel (Ez 47) reaparece em Apocalipse 22:1-2 como o rio de água da vida da Nova Jerusalém — conectando a visão profética ao cumprimento escatológico."),
QuizQuestion(id:356,question:"O que representam as sete festas de Israel em Levítico 23?",options:["Sete marcos da redenção profeticamente","Apenas celebrações agrícolas","Dias de descanso semanais","Festas inventadas por Moisés sem"],correctIndex:0,explanation:"As sete festas de Israel são o calendário profético da redenção. As quatro primaveras (Páscoa, Pães Asmos, Primícias, Pentecostes) foram cumpridas por Cristo e pelo Espírito no NT.",reference:"Levítico 23; 1 Coríntios 15:20-23",category:.geral,propheticMeaning:"Cristo morreu na Páscoa, foi sepultado nos Pães Asmos, ressuscitou nas Primícias e derramou o Espírito no Pentecostes — quatro festas cumpridas com precisão de calendário. As três do outono (Trombetas, Expiação, Tabernáculos) ainda aguardam cumprimento na segunda vinda."),
QuizQuestion(id:357,question:"O que é o 'Day of Atonement' / Dia da Expiação em Israel?",options:["A festa da colheita","Yom Kippur","A celebração do ano novo","O dia de luto pelo exílio"],correctIndex:1,explanation:"O Dia da Expiação (Yom Kippur, Lv 16) era o único dia em que o sumo-sacerdote entrava no Santo dos Santos com sangue para expiar os pecados de Israel.",reference:"Levítico 16:29-34",category:.geral,propheticMeaning:"Hebreus 9:11-12 explica que Cristo entrou no tabernáculo celestial com seu próprio sangue, 'obtendo redenção eterna' — o Yom Kippur definitivo, cumprindo todos os anteriores de uma vez por todas."),
QuizQuestion(id:358,question:"O que é a 'aliança abraâmica' e suas três promessas?",options:["A aliança da lei com Israel","A aliança do arco-íris com Noé","A aliança com Abraão incluindo: terra","A aliança da circuncisão apenas"],correctIndex:2,explanation:"Gênesis 12:1-3 registra a aliança com Abraão: terra (Canaã), descendência numerosa e bênção universal — 'em ti serão benditas todas as famílias da terra.'",reference:"Gênesis 12:1-3; Gálatas 3:16",category:.geral,propheticMeaning:"Paulo revela que a 'semente' de Abraão é Cristo (Gl 3:16) — a bênção a 'todas as nações' é o evangelho chegando a todos os povos pela Igreja de Cristo, cumprindo a promessa a Abraão."),
QuizQuestion(id:359,question:"O que é o 'Ano do Jubileu' em Levítico 25?",options:["Celebração do 50º aniversário do templo","Celebração da conquista de Canaã","A renovação anual do pacto","A cada 50 anos: libertação de escravos"],correctIndex:3,explanation:"O Jubileu (Lv 25) a cada 50 anos proclamava liberdade a cativos, retorno de propriedades e descanso da terra — a grande restauração social de Israel.",reference:"Levítico 25:10",category:.geral,propheticMeaning:"Jesus em Lucas 4:18-19 proclamou 'o ano aceitável do Senhor' (Is 61:1-2) — declarando que ele mesmo é o Jubileu definitivo: libertação dos cativos, vista aos cegos, pregação das boas novas."),
QuizQuestion(id:360,question:"O que Apocalipse 20 ensina sobre o milênio?",options:["Cristo reinará por mil anos após seu...","Que não haverá reinado de Cristo na terra","Que o mundo será destruído em mil anos","Que a Igreja reinará sem Cristo"],correctIndex:0,explanation:"Apocalipse 20:1-6 descreve um reinado de mil anos de Cristo com os que ressuscitaram na primeira ressurreição, com Satanás acorrentado — base das principais escatologias cristãs.",reference:"Apocalipse 20:1-6",category:.geral,propheticMeaning:"O milênio, qualquer que seja a interpretação, confirma que Cristo reina sobre toda a criação — cumprindo as profecias dos profetas sobre o reino de paz e justiça do Messias (Is 11:1-9; Sl 72)."),
QuizQuestion(id:361,question:"O que é o 'livro da vida' mencionado no Apocalipse?",options:["A lista de membros da Igreja","O registro celestial dos que pertencem","A Bíblia em si","Uma metáfora para a memória de Deus"],correctIndex:1,explanation:"Apocalipse 20:15: 'Aquele que não foi achado escrito no livro da vida foi lançado no lago de fogo.' O livro da vida é o registro dos redimidos.",reference:"Apocalipse 20:15; Filipenses 4:3",category:.geral,propheticMeaning:"Paulo menciona 'aqueles cujos nomes estão no livro da vida' (Fp 4:3) — a certeza da salvação repousa não na nossa fidelidade mas no registro celestial mantido pelo próprio Cristo."),
QuizQuestion(id:362,question:"O que representa o número 7 na Bíblia?",options:["Sorte","Pecado","O número da perfeição e completude","A quantidade de tribos de Israel"],correctIndex:2,explanation:"O número 7 representa perfeição e completude na Bíblia: sete dias da criação, sete festas, sete igrejas, sete selos, trombetas e taças no Apocalipse.",reference:"Gênesis 2:2; Apocalipse 1:4",category:.geral,propheticMeaning:"O sábado (7º dia) como repouso divino aponta ao descanso sabático final em Cristo (Hb 4:9-11) — o '7' na Bíblia sempre aponta para a completude da obra de Deus."),
QuizQuestion(id:363,question:"O que é o 'tabernáculo de Deus' em Apocalipse 21:3?",options:["O templo físico reconstruído","A Igreja como templo","O tabernáculo de Moisés glorificado","A habitação definitiva de Deus com os..."],correctIndex:3,explanation:"Apocalipse 21:3: 'Eis o tabernáculo de Deus com os homens. Ele habitará com eles... e Deus mesmo estará com eles.' É a culminação de toda a história da redenção.",reference:"Apocalipse 21:3",category:.geral,propheticMeaning:"O tabernáculo de Moisés (Deus habitando no acampamento), o templo de Salomão (Deus habitando em Sião), a encarnação (Deus habitando em carne) e Ap 21 (Deus habitando com todos) — a trajetória de Deus buscando habitar com sua criação."),
QuizQuestion(id:364,question:"O que é a 'teologia do pacto' ou 'teologia da aliança'?",options:["A compreensão de que a Bíblia inteira é","Estudo dos contratos comerciais bíblicos","A doutrina da predestinação","Estudo das festas de Israel"],correctIndex:0,explanation:"A teologia da aliança vê a Bíblia como história das alianças de Deus (Noé, Abraão, Moisés, Davi, Nova Aliança) — todas cumpridas e superadas na Nova Aliança em Cristo.",reference:"Hebreus 8:6; Jeremias 31:31-34",category:.geral,propheticMeaning:"As alianças anteriores são 'sombras' que apontam para a Nova Aliança — melhor (Hb 7:22), selada com sangue melhor (Hb 9:14), com mediador melhor (Hb 8:6) e promessas melhores (Hb 8:6)."),
QuizQuestion(id:365,question:"Qual é o significado profético da destruição do templo de Jerusalém em 70 d.C.?",options:["Foi um acidente histórico","Cumprimento da profecia de Jesus (Mt","Fim do povo judeu","Uma punição sem propósito redentor"],correctIndex:1,explanation:"Jesus profetizou em 70 d.C. a destruição do templo: 'não ficará pedra sobre pedra.' Cumprida pela invasão romana, marcou o fim definitivo do sistema sacrificial levítico.",reference:"Mateus 24:2; Hebreus 10:18",category:.geral,propheticMeaning:"Com o templo destruído, Hebreus 10:18 já afirmara: 'onde há remissão destas... não há mais oferta pelo pecado.' Deus encerrou o sistema tipológico porque o cumprimento havia chegado em Cristo."),
QuizQuestion(id:366,question:"O que é a 'teologia da libertação'?",options:["A doutrina da segunda vinda","A doutrina da justificação","Uma corrente teológica que enfatiza que","Teologia exclusiva da América Latina"],correctIndex:2,explanation:"A teologia da libertação (séc. XX, especialmente na América Latina) enfatiza a dimensão sociopolítica do evangelho, ligando a salvação à libertação dos pobres e oprimidos.",reference:"Lucas 4:18-19; Amós 5:24",category:.geral,propheticMeaning:"Seja qual for a avaliação da teologia da libertação, a Bíblia claramente liga salvação e justiça: os profetas clamam por justiça social, Jesus proclama boas novas aos pobres, e Tiago conecta fé viva a cuidado dos necessitados."),
QuizQuestion(id:367,question:"O que significa 'shalom' em hebraico?",options:["Apenas paz interior","Ausência de guerra apenas","Prosperidade material","Paz em sentido pleno:"],correctIndex:3,explanation:"Shalom é muito mais que ausência de conflito — é completude, bem-estar e harmonia em todas as dimensões da existência, individual e comunitária.",reference:"Números 6:24-26; João 14:27",category:.geral,propheticMeaning:"Jesus é o 'Príncipe da Paz' (Is 9:6) — o shalom definitivo: reconciliação com Deus (Rm 5:1) que produz paz entre pessoas (Ef 2:14) e aguarda restauração da criação (Rm 8:21)."),
QuizQuestion(id:368,question:"O que é o 'sacerdócio de todos os crentes'?",options:["A doutrina de que todos os crentes têm","Todos podem ser padres","Todos devem ministrar na Igreja de forma","Abolição de qualquer liderança"],correctIndex:0,explanation:"1 Pedro 2:9: 'Vós sois... sacerdócio real.' O crente tem acesso direto a Deus em Cristo, pode interceder pelos outros e oferecer sacrifícios espirituais.",reference:"1 Pedro 2:9; Hebreus 10:19-22",category:.geral,propheticMeaning:"O sacerdócio universal cumpre Êxodo 19:6: 'sereis para mim um reino de sacerdotes' — prometido a Israel mas realizado na Igreja de Cristo que rasga o véu do templo."),
QuizQuestion(id:369,question:"O que o livro de Rute ensina sobre o 'parente redentor'?",options:["Que os parentes devem sempre emprestar","O conceito de go'el (parente redentor)","Que mulheres podem herdar terras","As leis de casamento em Israel"],correctIndex:1,explanation:"O go'el (parente redentor) em Israel tinha direito de comprar de volta propriedade perdida e levantar descendência para parentes sem filhos. Boaz cumpre esse papel para Rute.",reference:"Rute 4:9-10",category:.geral,propheticMeaning:"Cristo como nosso Go'el: ele tem direito (como nosso Irmão, Hb 2:11), capacidade (como Deus, Hb 7:25) e pagou o preço (com seu sangue, 1 Pe 1:18-19) para nos resgatar da escravidão do pecado."),
QuizQuestion(id:370,question:"O que Paulo ensina sobre a eleição e o livre-arbítrio em Romanos 9?",options:["Livre-arbítrio sem eleição divina","Que ninguém tem responsabilidade","Eleição divina soberana sem negar a...","Que Deus não elege ninguém"],correctIndex:2,explanation:"Romanos 9:14-18 defende a soberania divina na eleição: 'terei misericórdia de quem eu tiver misericórdia' — não é injustiça mas liberdade soberana de Deus para agir conforme sua vontade.",reference:"Romanos 9:14-18",category:.geral,propheticMeaning:"A tensão soberania/liberdade é um dos maiores mistérios teológicos — a Escritura afirma ambos sem resolver a tensão racionalmente, convidando à humildade diante do Deus insondável (Rm 11:33-36)."),
QuizQuestion(id:371,question:"Qual é a importância de Abraão como 'pai da fé'?",options:["Por ter muitos filhos","Por ter construído altares","Por ter obedecido a todos os mandamentos","Por ter crido em Deus quando não havia"],correctIndex:3,explanation:"Abraão 'creu a Deus e isso lhe foi imputado como justiça' (Gn 15:6) — Paulo usa esse versículo em Romanos 4 como prova de que a justificação pela fé sempre foi o caminho de Deus.",reference:"Gênesis 15:6; Romanos 4:3",category:.geral,propheticMeaning:"Abraão crendo na promessa de um filho quando era 'como que morto' e Sara estéril (Rm 4:19) é tipo de crer na ressurreição — a mesma fé que justifica ao crer que 'Deus ressuscitou Jesus dos mortos' (Rm 10:9)."),
QuizQuestion(id:372,question:"O que Paulo diz sobre a lei e a graça em Romanos 6:14?",options:["'Não estais sob a lei, mas sob a graça'","A lei salva","Graça permite qualquer comportamento","A lei foi abolida completamente"],correctIndex:0,explanation:"Romanos 6:14: 'O pecado não terá domínio sobre vós, porque não estais sob a lei, mas sob a graça' — libertação da condenação da lei, não licença para pecar.",reference:"Romanos 6:14-15",category:.geral,propheticMeaning:"'Não estais sob a lei mas sob a graça' não aboliu a lei mas mudou a relação com ela — de obrigação externa para expressão de amor interno, cumprida pelo Espírito que derrama o amor de Deus (Rm 5:5)."),
QuizQuestion(id:373,question:"Qual é o tema do Salmo 119?",options:["A queda de Sião","O maior Salmo: meditação sobre a Palavra","O sofrimento de Davi no exílio","A vitória sobre os inimigos de Israel"],correctIndex:1,explanation:"O Salmo 119 é o mais longo da Bíblia (176 versículos) e um acrostico hebraico exaltando a Palavra de Deus em todas as suas formas.",reference:"Salmos 119:105",category:.geral,propheticMeaning:"'A tua palavra é lâmpada para os meus pés e luz para o meu caminho' (Sl 119:105) — o salmista sabia que sem a Palavra divina, o caminho da vida é impenetrável; o cristão tem o Espírito que ilumina a mesma Palavra."),
QuizQuestion(id:374,question:"O que aconteceu na história de Sodoma e Gomorra?",options:["Uma batalha entre cidades","Uma grande inundação","Duas cidades destruídas por","Um terremoto natural"],correctIndex:2,explanation:"Sodoma e Gomorra foram destruídas por Deus com chuva de fogo e enxofre por causa de sua grande maldade, antes que Ló e sua família fossem retirados.",reference:"Gênesis 19:24-25",category:.geral,propheticMeaning:"Jesus usou Sodoma e Gomorra como exemplo de juízo que virá sobre os que rejeitam o evangelho (Mt 10:15; Lc 17:29) — o destino das cidades ímpia é modelo escatológico do juízo final."),
QuizQuestion(id:375,question:"O que significa a chamada 'proto-evangelho' em Gênesis 3:15?",options:["A primeira lei da Bíblia","A primeira aliança com Noé","O primeiro sacrifício de Adão","A primeira promessa do Messias:"],correctIndex:3,explanation:"Gênesis 3:15 é o 'proto-evangelho' (primeira boa notícia): a semente da mulher esmagará a cabeça da serpente, sofrendo apenas ferida no calcanhar — a primeira profecia do Messias.",reference:"Gênesis 3:15",category:.geral,propheticMeaning:"Esta primeira profecia é cumprida em Cristo: ele esmagou a cabeça de Satanás na cruz (Jo 12:31; Cl 2:15), sofrendo o 'calcanhar' (morte temporária) mas ressurreto vitorioso. Toda a Bíblia desenvolve esta semente de Gn 3:15."),
QuizQuestion(id:376,question:"Qual é a promessa do arco-íris em Gênesis 9?",options:["Que Deus nunca mais destruirá a","Que nunca mais choverá","Que Israel será protegido","Que o sol nunca se apagará"],correctIndex:0,explanation:"Após o dilúvio, Deus estabeleceu aliança com Noé: nunca mais destruiria toda a terra com água, com o arco-íris como sinal perpétuo.",reference:"Gênesis 9:13-15",category:.geral,propheticMeaning:"O arco-íris reaparece ao redor do trono de Deus em Ap 4:3 e sobre o anjo em Ap 10:1 — lembrando que o Juiz é também o Deus da aliança fiel que nunca quebra suas promessas."),
QuizQuestion(id:377,question:"O que foi a Torre de Babel?",options:["Um templo de Israel","Uma tentativa de construir torre","Uma armadilha para inimigos","O primeiro templo de Deus"],correctIndex:1,explanation:"Gênesis 11: os povos da terra construíram uma torre para 'chegar ao céu' em orgulho e desobediência. Deus confundiu as línguas e dispersou as nações.",reference:"Gênesis 11:4-9",category:.geral,propheticMeaning:"O Pentecostes reversa Babel: onde Babel dividiu as línguas (At 2:4-11), o Espírito reuniu os povos na compreensão do evangelho — tipo da reunião final de todas as nações ao redor do trono do Cordeiro (Ap 7:9)."),
QuizQuestion(id:378,question:"Quem foi Melquisedeque?",options:["Um rei de Israel","Um profeta menor","Rei de Salém e","O pai de Abraão"],correctIndex:2,explanation:"Melquisedeque (Gn 14:18-20) era rei de Salém e sacerdote do Deus Altíssimo — misterioso personagem sem genealogia registrada, usado em Hebreus como tipo do sacerdócio eterno de Cristo.",reference:"Gênesis 14:18-20; Hebreus 7:1-3",category:.geral,propheticMeaning:"Hebreus 7 desenvolve extensamente o tipo: Melquisedeque sem começo nem fim registrados é tipo de Cristo como 'sacerdote para sempre' (Sl 110:4) — eterno, não baseado em linhagem mas em vida indissolúvel (Hb 7:16)."),
QuizQuestion(id:379,question:"O que Paulo ensina sobre o corpo na ressurreição?",options:["Corpo físico exatamente igual ao atual","Nenhum corpo, apenas alma","Corpo completamente diferente sem","'Semeado corpo natural"],correctIndex:3,explanation:"1 Coríntios 15:42-44: o corpo ressurreto será incorruptível, glorioso, poderoso e espiritual — não imaterial mas transformado, como o corpo ressurreto de Cristo.",reference:"1 Coríntios 15:42-44",category:.geral,propheticMeaning:"O corpo ressurreto de Jesus — que podia ser tocado (Jo 20:27) e comer (Lc 24:42-43) mas também passar por portas (Jo 20:19) — é o protótipo do nosso: real e material mas transformado e glorificado."),
QuizQuestion(id:380,question:"O que ensina o Salmo 2 sobre o Messias?",options:["'Pedi-me e te darei as nações como...","O Messias reinará apenas em Israel","O Messias virá apenas como sofredor","O Messias é apenas profeta"],correctIndex:0,explanation:"O Salmo 2 é um dos mais centrais Salmos messiânicos: o Filho ungido (Messias) recebe as nações como herança e reina sobre toda a terra, apesar da rebelião dos governantes.",reference:"Salmos 2:7-8; Atos 13:33; Hebreus 1:5",category:.geral,propheticMeaning:"O Salmo 2 é citado no NT em referência ao batismo de Jesus, à ressurreição e à exaltação de Cristo — 'hoje te gerei' cumprido na ressurreição (At 13:33) quando Jesus foi declarado Filho de Deus com poder (Rm 1:4)."),
]
